import {
  ACTIVE_RUN_STORAGE_KEY,
  RUN_INDEX_STORAGE_KEY,
  clearActiveRun,
  formatRunDate,
  loadActiveRun,
  loadRunIndex,
  runIndexEntryFromState,
  saveActiveRun,
  upsertRunIndexEntry,
  type RunIndexStorage,
} from "./model";
import { buildReplayFrames } from "./replay";

describe("run index", () => {
  it("stores list rows by outcome, depth, and date with active-run persistence", () => {
    const storage = new MemoryStorage();
    const state = {
      ...createInitialState("run-index-store"),
      run: {
        ...createInitialState("run-index-store").run,
        terminalStatus: "LOSS" as const,
        depth: 3,
        turn: 42,
      },
    };
    const entry = runIndexEntryFromState({
      state,
      createdAt: "2026-06-12T01:02:03.000Z",
      traceContent: "{}\n",
    });

    expect(entry).toMatchObject({
      outcome: "defeat",
      depth: 3,
      turns: 42,
    });
    expect(formatRunDate(entry.createdAt)).toBe("2026-06-12");
    upsertRunIndexEntry(storage, entry);
    expect(loadRunIndex(storage)).toEqual([entry]);
    expect(storage.getItem(RUN_INDEX_STORAGE_KEY)).toContain(entry.runId);

    saveActiveRun(storage, {
      runId: state.run.runId,
      seed: state.run.seed,
      createdAt: entry.createdAt,
      gameState: state,
      traceContent: entry.traceContent,
    });
    expect(loadActiveRun(storage)?.runId).toBe(state.run.runId);
    clearActiveRun(storage);
    expect(storage.getItem(ACTIVE_RUN_STORAGE_KEY)).toBeNull();
  });

  it("steps a fixture trace through replay verification and the real grid renderer", () => {
    const session = createClientGameSession({ seed: "run-index-replay" });
    session.step({ kind: "wait" });
    session.step({ kind: "wait" });
    const replay = buildReplayFrames(session.traceContent);

    expect(replay.status).toBe("identical");
    expect(replay.frames).toHaveLength(3);
    const frame = replay.frames[1];
    if (frame === undefined) {
      throw new Error("expected replay frame");
    }

    const markup = renderToStaticMarkup(createElement(GameGrid, { state: frame.state }));
    expect(markup).toContain('role="grid"');
    expect(markup).toContain('data-glyph="@');
  });
});

class MemoryStorage implements RunIndexStorage {
  private readonly values = new Map<string, string>();

  getItem(key: string): string | null {
    return this.values.get(key) ?? null;
  }

  setItem(key: string, value: string): void {
    this.values.set(key, value);
  }

  removeItem(key: string): void {
    this.values.delete(key);
  }
}

import { describe, expect, it } from "vitest";

import {
  ARRIVAL_RITUAL_MS,
  READY_THEATER_MS,
  STAIRS_CAP_MS,
  createDescendingTransition,
  markTransitionFloorReady,
  shouldAutoEnterFloor,
  shouldResumePlay,
  startArrivalRitual,
  transitionPresentation,
  transitionPresentationForSource,
  type FloorControllerState,
} from "./model";

describe("floor transition UX", () => {
  it("projects ready, in-flight, and none controller states without exposing generation state as copy", () => {
    const states: readonly FloorControllerState[] = ["ready", "in_flight", "none"];

    const presentations = states.map((controllerState) =>
      transitionPresentation(
        createDescendingTransition({
          depth: 4,
          whisper: "The Deep closes one room and opens another.",
          controllerState,
          startedAtMs: 0,
        }),
        400,
      ),
    );

    expect(presentations[0]).toMatchObject({
      floorLabel: "Floor 4",
      shimmerVisible: false,
      awaitingFloor: false,
    });
    expect(presentations[1]).toMatchObject({
      floorLabel: "Floor 4",
      shimmerVisible: true,
      awaitingFloor: true,
    });
    expect(presentations[2]).toMatchObject({
      floorLabel: "Floor 4",
      shimmerVisible: false,
      awaitingFloor: true,
    });
    expect(
      presentations.every((presentation) =>
        !/generat|fallback|error|loading/i.test(presentation.whisper),
      ),
    ).toBe(true);
  });

  it("serves generated and fallback floors through identical presentation props", () => {
    expect(transitionPresentationForSource("generated")).toEqual(
      transitionPresentationForSource("fallback"),
    );
  });

  it("caps shimmer progress and allows interrupt only after the floor is ready", () => {
    const waiting = createDescendingTransition({
      depth: 2,
      whisper: "A lantern-breath thins below the stair.",
      controllerState: "in_flight",
      startedAtMs: 0,
    });

    expect(transitionPresentation(waiting, STAIRS_CAP_MS * 2)).toMatchObject({
      shimmerVisible: true,
      shimmerPercent: 100,
      skipEnabled: false,
    });

    const ready = markTransitionFloorReady(waiting, 1_100, "generated");
    expect(transitionPresentation(ready, 1_100).skipEnabled).toBe(true);
    expect(shouldAutoEnterFloor(ready, 1_100)).toBe(true);
  });

  it("keeps ready floors in pure theater for 1-2s unless skipped", () => {
    const ready = markTransitionFloorReady(
      createDescendingTransition({
        depth: 3,
        whisper: "Stone remembers the last warm footprint.",
        controllerState: "ready",
        startedAtMs: 0,
      }),
      50,
      "generated",
    );

    expect(shouldAutoEnterFloor(ready, READY_THEATER_MS - 1)).toBe(false);
    expect(shouldAutoEnterFloor(ready, READY_THEATER_MS)).toBe(true);
  });

  it("models the arrival ritual before play resumes", () => {
    const arrival = startArrivalRitual(
      markTransitionFloorReady(
        createDescendingTransition({
          depth: 5,
          whisper: "Quiet dust gathers where names are unwritten.",
          controllerState: "ready",
          startedAtMs: 0,
        }),
        100,
        "generated",
      ),
      1_000,
    );

    expect(transitionPresentation(arrival, 1_800)).toMatchObject({
      phase: "arrival",
      entrancePulse: true,
      arrivalProgress: 0.4,
    });
    expect(shouldResumePlay(arrival, 1_000 + ARRIVAL_RITUAL_MS - 1)).toBe(false);
    expect(shouldResumePlay(arrival, 1_000 + ARRIVAL_RITUAL_MS)).toBe(true);
  });
});

